/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>This code is used to show/hide features for Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(InventValueExecutionHistory, InventValueProcess)).visible(!currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventValueExecutionHistory, ETGSPAINInventValueProcess)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventValueExecutionHistory, ETG_InventValueProcess)).visible(!currentCompanyIsSpanishCompany);

}
